console.log('Root layout və page yaradıldı');

// app/dashboard/layout.js
export default function DashboardLayout({ children }) {
  return (
    <div>
      <nav>Dashboard Naviqasiya</nav>
      <main>{children}</main>
    </div>
  );
}

// app/dashboard/page.js
export default function Dashboard() {
  return <h1>Dashboard Səhifəsi</h1>;
}

console.log('Nested layout yaradıldı');

// app/counter/page.js (client component)
'use client';

import { useState } from 'react';

export default function Counter() {
  const [count, setCount] = useState(0);

  return (
    <div>
      <p>Say: {count}</p>
      <button onClick={() => setCount(count + 1)}>Artır</button>
    </div>
  );
}

console.log('Client component yaradıldı');

// app/loading.js
export default function Loading() {
  return <p>Yüklənir...</p>;
}

// app/error.js
'use client';

export default function Error({ error }) {
  return <p>Xəta: {error.message}</p>;
}

console.log('Loading və error UI yaradıldı');

